"""Minimal BPE training from scratch — illustrates the core algorithm."""
from collections import Counter


def get_pair_counts(vocab: dict[str, int]) -> Counter:
    """Count every adjacent symbol pair weighted by word frequency."""
    pairs: Counter = Counter()
    for word, freq in vocab.items():
        symbols = word.split()
        for i in range(len(symbols) - 1):
            pairs[(symbols[i], symbols[i + 1])] += freq
    return pairs


def merge_pair(pair: tuple[str, str], vocab: dict[str, int]) -> dict[str, int]:
    """Replace every occurrence of 'a b' with 'ab' in the vocabulary."""
    bigram = " ".join(pair)
    merged = "".join(pair)
    return {word.replace(bigram, merged): freq for word, freq in vocab.items()}


def bpe_train(corpus: list[str], num_merges: int) -> list[tuple[str, str]]:
    """Run BPE training and return the ordered merge table."""
    word_counts: Counter = Counter(corpus)
    # Each word starts as space-separated characters with an end-of-word marker
    vocab = {
        " ".join(list(word)) + " </w>": freq
        for word, freq in word_counts.items()
    }

    merges: list[tuple[str, str]] = []
    for step in range(num_merges):
        pairs = get_pair_counts(vocab)
        if not pairs:
            break
        best = max(pairs, key=lambda p: pairs[p])
        vocab = merge_pair(best, vocab)
        merges.append(best)
        print(f"Step {step + 1:3d}: merged {best!r:24s}  freq={pairs[best]}")

    return merges


# Toy corpus — same example used in the original BPE paper
corpus = (
    ["low"] * 5 + ["lower"] * 2 + ["newest"] * 6 +
    ["widest"] * 3 + ["wide"] * 4 + ["new"] * 8
)

print("=== BPE Training (12 merges) ===")
merges = bpe_train(corpus, num_merges=12)
print("\nFinal merge table:")
for i, (a, b) in enumerate(merges, 1):
    print(f"  {i:2d}. '{a}' + '{b}' -> '{a + b}'")
